using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record TicketRequest(string Subject, string Description, int Priority);

public record PredictionResponse(
    string PredictedCategory,
    Dictionary<string, float> Confidence);

public record EvaluationResponse(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    Dictionary<string, CategoryMetrics> PerCategoryMetrics);

public record CategoryMetrics(
    double Precision,
    double Recall,
    double F1Score);

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResponse _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);

        // Extract the ordered category labels from the trained Label key column
        var schema = _model.GetOutputSchema(split.TrainSet.Schema);
        var labelColumn = schema["Label"];
        var keyType = labelColumn.Type as KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        _evaluationMetrics = Evaluate(split.TestSet);

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticket = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticket);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse(prediction.PredictedCategory, confidence);
    }

    public EvaluationResponse GetMetrics() => _evaluationMetrics;

    private EvaluationResponse Evaluate(IDataView testData)
    {
        var predictions = _model.Transform(testData);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var perCategory = new Dictionary<string, CategoryMetrics>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count && i < _categoryLabels.Length; i++)
        {
            perCategory[_categoryLabels[i]] = new CategoryMetrics(
                Precision: Round(metrics.ConfusionMatrix.PerClassPrecision[i]),
                Recall: Round(metrics.ConfusionMatrix.PerClassRecall[i]),
                F1Score: Round(CalculateF1(
                    metrics.ConfusionMatrix.PerClassPrecision[i],
                    metrics.ConfusionMatrix.PerClassRecall[i])));
        }

        return new EvaluationResponse(
            MacroAccuracy: Round(metrics.MacroAccuracy),
            MicroAccuracy: Round(metrics.MicroAccuracy),
            LogLoss: Round(metrics.LogLoss),
            LogLossReduction: Round(metrics.LogLossReduction),
            PerCategoryMetrics: perCategory);
    }

    private static double CalculateF1(double precision, double recall) =>
        precision + recall == 0 ? 0 : 2 * precision * recall / (precision + recall);

    private static double Round(double value) =>
        Math.Round(value, 4);
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var prediction = _classifier.Predict(request);
        return Ok(prediction);
    }

    /// <summary>
    /// Returns model evaluation metrics from the train/test split.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

