using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var prediction = _classifier.Predict(request);
        return Ok(prediction);
    }

    /// <summary>
    /// Returns model evaluation metrics from the train/test split.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

